{
  "title": "फ्यू-शॉट उदाहरण",
  "group": "प्रॉम्प्ट संरचना",
  "options": [
    {
      "text": "जितने ज्यादा उदाहरण, उतने बेहतर परिणाम"
    },
    {
      "text": "प्रॉम्प्ट में 3–5 उच्च-गुणवत्ता वाले और विविध उदाहरण"
    },
    {
      "text": "फ्यू-शॉट उदाहरण केवल वर्गीकरण कार्यों के लिए काम आते हैं"
    },
    {
      "text": "उदाहरण यूज़र क्वेरी के बाद होने चाहिए, पहले नहीं"
    }
  ],
  "questionProse": [
    "ज्यादातर प्रोडक्शन यूज़ केस के लिए, फ्यू-शॉट उदाहरणों की सर्वोत्तम रणनीति क्या है:"
  ],
  "explanationProse": [
    "फ्यू-शॉट उदाहरण आउटपुट की स्थिरता और फॉर्मेट का सटीक पालन दोनों को काफी बेहतर बना देते हैं। ज्यादातर टास्क के लिए स्वीट स्पॉट है **3–5 उच्च-गुणवत्ता वाले और विविध उदाहरण**。\n\n    और ज्यादा क्यों नहीं? हर उदाहरण टोकन खर्च करता है। 5–10 उदाहरणों के बाद, अतिरिक्त लाभ घटने लगता है जबकि टोकन लागत बढ़ती ही रहती है। ज्यादा उदाहरण देने से मॉडल के उदाहरणों पर ओवरफिट होने और असली पैटर्न को समझने में असफल रहने की संभावना बढ़ जाती है。\n\n    विविधता क्यों ज़रूरी है: अगर आपके सभी उदाहरण एक ही तरह के इनपुट के हैं, तो मॉडल एज केस (edge cases) पर अच्छी तरह जेनरलाइज़ नहीं कर पाएगा। अपने सबसे महत्वपूर्ण वेरिएशन को कवर करने वाले उदाहरण ज़रूर शामिल करें。\n\n    प्लेसमेंट: उदाहरण यूज़र क्वेरी के *पहले* जाने चाहिए, सिस्टम प्रॉम्प्ट के हिस्से के तौर पर या प्रीफिल्ड कन्वर्सेशन टर्न्स के रूप में — बाद में नहीं।"
  ]
}
